use crate::config::{Cli, Command};
use crate::content::{load_content, start_file_watcher};
use crate::routes::{AppState, router};
use axum::serve;
use clap::Parser;
use std::path::PathBuf;
use std::sync::Arc;
use tokio::net::TcpListener;
use tokio::sync::RwLock;
use tower_http::services::ServeDir;
use tracing::info;

#[tokio::main]
async fn main() -> anyhow::Result<()> {
    tracing_subscriber::fmt()
        .with_env_filter(
            tracing_subscriber::EnvFilter::try_from_default_env()
                .unwrap_or_else(|_| "mizushi=info".into()),
        )
        .init();

    let cli = Cli::parse();

    match cli.command {
        Command::Serve {
            port,
            content,
            static_dir,
        } => run_server(port, PathBuf::from(content), PathBuf::from(static_dir)).await,
        Command::Export {
            content,
            static_dir,
            output,
        } => run_export(
            PathBuf::from(content),
            PathBuf::from(static_dir),
            PathBuf::from(output),
        ),
    }
}

fn run_export(
    content_dir: PathBuf,
    static_dir: PathBuf,
    output_dir: PathBuf,
) -> anyhow::Result<()> {
    let site = load_content(&content_dir)?;
    export::export_site(&site, &static_dir, &output_dir)?;
    Ok(())
}

async fn run_server(port: u16, content_dir: PathBuf, static_dir: PathBuf) -> anyhow::Result<()> {
    let site = load_content(&content_dir)?;
    let site = Arc::new(RwLock::new(site));

    // Start file watcher for live content reload
    let watcher_site = site.clone();
    let watcher_dir = content_dir.clone();
    let _watcher = start_file_watcher(watcher_dir, watcher_site)?;

    let state = AppState { site };

    let app = router(state)
        .nest_service("/css", ServeDir::new(static_dir.join("css")))
        .nest_service("/js", ServeDir::new(static_dir.join("js")))
        .nest_service("/images", ServeDir::new(static_dir.join("images")));

    let addr = format!("0.0.0.0:{}", port);
    info!("Starting mizushi on http://{}", addr);

    let listener = TcpListener::bind(&addr).await?;
    serve(listener, app).await?;

    Ok(())
}


